36→/**
37→ * Invoke the AWS Lambda embedding function to generate an OpenAI embedding
38→ * for the given text.
39→ *
40→ * @param text - The text to embed.
41→ * @returns The embedding vector (number[]).
42→ * @throws If the Lambda invocation fails or returns an error.
43→ */
44→export async function generateEmbedding(text: string): Promise<number[]> {
45→  const command = new InvokeCommand({
46→    FunctionName: config.AWS_LAMBDA_FUNCTION_NAME,
47→    Payload: new TextEncoder().encode(JSON.stringify({ text })),
48→  });
49→
50→  const response = await getLambdaClient().send(command);
51→
52→  if (response.FunctionError) {
53→    throw new Error(
54→      `Lambda function error: ${response.FunctionError} — ${
55→        response.Payload
56→          ? new TextDecoder().decode(response.Payload)
57→          : "no payload"
58→      }`
59→    );
60→  }
61→
62→  if (!response.Payload) {
63→    throw new Error("Lambda returned no payload");
64→  }
65→
66→  const raw = new TextDecoder().decode(response.Payload);
67→  const lambdaResult: LambdaPayload = JSON.parse(raw);
68→
69→  if (lambdaResult.statusCode !== 200) {
70→    throw new Error(
71→      `Lambda returned status ${lambdaResult.statusCode}: ${lambdaResult.body}`
72→    );
73→  }
74→
75→  const body: LambdaResponseBody = JSON.parse(lambdaResult.body);
76→
77→  if (!Array.isArray(body.embedding) || body.embedding.length === 0) {
78→    throw new Error("Lambda returned an invalid or empty embedding");
79→  }
80→
81→  return body.embedding;
82→}
