185→// ---------------------------------------------------------------------------
186→// Transport selection and startup
187→// ---------------------------------------------------------------------------
188→
189→async function main(): Promise<void> {
190→  const useSSE =
191→    process.argv.includes("--sse") || Boolean(process.env.SSE_PORT);
192→
193→  if (useSSE) {
194→    const port = parseInt(process.env.SSE_PORT || "3001", 10);
195→    const transports: Record<string, SSEServerTransport> = {};
196→
197→    const httpServer = createServer(
198→      async (req: IncomingMessage, res: ServerResponse) => {
199→        const url = new URL(req.url || "/", `http://localhost:${port}`);
200→
201→        if (req.method === "GET" && url.pathname === "/sse") {
202→          // New SSE connection
203→          const transport = new SSEServerTransport("/messages", res);
204→          transports[transport.sessionId] = transport;
205→          await server.connect(transport);
206→          return;
207→        }
208→
209→        if (req.method === "POST" && url.pathname === "/messages") {
210→          const sessionId = url.searchParams.get("sessionId");
211→          if (!sessionId || !transports[sessionId]) {
212→            res.writeHead(400);
213→            res.end("Invalid or missing sessionId");
214→            return;
215→          }
216→          await transports[sessionId].handlePostMessage(req, res);
217→          return;
218→        }
219→
220→        res.writeHead(404);
221→        res.end("Not found");
222→      }
223→    );
224→
225→    httpServer.listen(port, () => {
226→      console.error(`[research7-mcp] SSE server listening on port ${port}`);
227→    });
228→  } else {
229→    // Default: stdio transport
230→    const transport = new StdioServerTransport();
231→    await server.connect(transport);
232→    console.error("[research7-mcp] Server running on stdio");
233→  }
234→}
235→
236→main().catch((err) => {
237→  console.error("Fatal error starting MCP server:", err);
238→  process.exit(1);
239→});
